    [DataRow(@"[""Hello"", ""there"", ""again"", ""beautiful"", ""extraordinary"", ""magnificent"", ""glorious"", 3.0]", "Hellothereagainbeautifulextraordinarymagnificentglorious3.0")]
    [DataRow(@"[null, ""there"", ""again"", ""beautiful"", ""extraordinary"", ""magnificent"", ""glorious"", ""world""]", "nullthereagainbeautifulextraordinarymagnificentgloriousworld")]
    [DataRow(@"[""Hello"", ""there"", ""again"", ""beautiful"", ""extraordinary"", ""magnificent"", ""glorious"", null]", "Hellothereagainbeautifulextraordinarymagnificentgloriousnull")]
    [DataRow(@"[[1,2,3], ""there"", ""again"", ""beautiful"", ""extraordinary"", ""magnificent"", ""glorious"", ""world""]", "[1,2,3]thereagainbeautifulextraordinarymagnificentgloriousworld")]
    [DataRow(@"[""Hello"", ""there"", ""again"", ""beautiful"", ""extraordinary"", ""magnificent"", ""glorious"", [1,2,3]]", "Hellothereagainbeautifulextraordinarymagnificentglorious[1,2,3]")]
    [DataRow(@"[{""foo"": 3}, ""there"", ""again"", ""beautiful"", ""extraordinary"", ""magnificent"", ""glorious"", ""world""]", "{\"foo\":3}thereagainbeautifulextraordinarymagnificentgloriousworld")]
    [DataRow(@"[""Hello"", ""there"", ""again"", ""beautiful"", ""extraordinary"", ""magnificent"", ""glorious"", {""foo"": 3}]", "Hellothereagainbeautifulextraordinarymagnificentglorious{\"foo\":3}")]
    [DataRow(@"[""there"", true, ""world""]", "theretrueworld")]
    [DataRow(@"[""there"", 3.0, ""world""]", "there3.0world")]
    [DataRow(@"[""there"", null, ""world""]", "therenullworld")]
    [DataRow(@"[""there"", [1,2,3], ""world""]", "there[1,2,3]world")]
    [DataRow(@"[""there"", {""foo"": 3}, ""world""]", "there{\"foo\":3}world")]
    [TestMethod]
    public void Concatenate_JsonString(string jsonArrayValue, string expectedResult)
    {
        JsonArray array = JsonArray.ParseValue(Encoding.UTF8.GetBytes(jsonArrayValue));
        Span<byte> buffer = stackalloc byte[256];
        JsonString result = array.GetArrayLength() switch
        {
            2 => JsonString.Concatenate(buffer, array[0], array[1]),
            3 => JsonString.Concatenate(buffer, array[0], array[1], array[2]),
            4 => JsonString.Concatenate(buffer, array[0], array[1], array[2], array[3]),
            5 => JsonString.Concatenate(buffer, array[0], array[1], array[2], array[3], array[4]),
            6 => JsonString.Concatenate(buffer, array[0], array[1], array[2], array[3], array[4], array[5]),
            7 => JsonString.Concatenate(buffer, array[0], array[1], array[2], array[3], array[4], array[5], array[6]),
            8 => JsonString.Concatenate(buffer, array[0], array[1], array[2], array[3], array[4], array[5], array[6], array[7]),
            _ => throw new InvalidOperationException("Unsupported number of items"),
        };
        Assert.AreEqual(new JsonString(expectedResult), result.AsString);
    }

