    [TestMethod]
    public void Concatenate_JsonDate(string jsonArrayValue, string expectedResult)
    {
        JsonArray array = JsonArray.ParseValue(Encoding.UTF8.GetBytes(jsonArrayValue));
        Span<byte> buffer = stackalloc byte[256];
        JsonDate result = array.GetArrayLength() switch
        {
            2 => JsonDate.Concatenate(buffer, array[0], array[1]),
            3 => JsonDate.Concatenate(buffer, array[0], array[1], array[2]),
            4 => JsonDate.Concatenate(buffer, array[0], array[1], array[2], array[3]),
            5 => JsonDate.Concatenate(buffer, array[0], array[1], array[2], array[3], array[4]),
            6 => JsonDate.Concatenate(buffer, array[0], array[1], array[2], array[3], array[4], array[5]),
            7 => JsonDate.Concatenate(buffer, array[0], array[1], array[2], array[3], array[4], array[5], array[6]),
            8 => JsonDate.Concatenate(buffer, array[0], array[1], array[2], array[3], array[4], array[5], array[6], array[7]),
            _ => throw new InvalidOperationException("Unsupported number of items"),
        };
        Assert.AreEqual(new JsonString(expectedResult), result.AsString);
    }

