        Span<byte> buffer = stackalloc byte[256];
        JsonEmail result = array.GetArrayLength() switch
        {
            2 => JsonEmail.Concatenate(buffer, array[0], array[1]),
            3 => JsonEmail.Concatenate(buffer, array[0], array[1], array[2]),
            4 => JsonEmail.Concatenate(buffer, array[0], array[1], array[2], array[3]),
            5 => JsonEmail.Concatenate(buffer, array[0], array[1], array[2], array[3], array[4]),
            6 => JsonEmail.Concatenate(buffer, array[0], array[1], array[2], array[3], array[4], array[5]),
            7 => JsonEmail.Concatenate(buffer, array[0], array[1], array[2], array[3], array[4], array[5], array[6]),
            8 => JsonEmail.Concatenate(buffer, array[0], array[1], array[2], array[3], array[4], array[5], array[6], array[7]),
            _ => throw new InvalidOperationException("Unsupported number of items"),
        };
        Assert.AreEqual(new JsonString(expectedResult), result.AsString);
    }

