    {
        JsonArray array = JsonArray.ParseValue(Encoding.UTF8.GetBytes(jsonArrayValue));
        Span<byte> buffer = stackalloc byte[256];
        JsonIdnEmail result = array.GetArrayLength() switch
        {
            2 => JsonIdnEmail.Concatenate(buffer, array[0], array[1]),
            3 => JsonIdnEmail.Concatenate(buffer, array[0], array[1], array[2]),
            4 => JsonIdnEmail.Concatenate(buffer, array[0], array[1], array[2], array[3]),
            5 => JsonIdnEmail.Concatenate(buffer, array[0], array[1], array[2], array[3], array[4]),
            6 => JsonIdnEmail.Concatenate(buffer, array[0], array[1], array[2], array[3], array[4], array[5]),
            7 => JsonIdnEmail.Concatenate(buffer, array[0], array[1], array[2], array[3], array[4], array[5], array[6]),
            8 => JsonIdnEmail.Concatenate(buffer, array[0], array[1], array[2], array[3], array[4], array[5], array[6], array[7]),
            _ => throw new InvalidOperationException("Unsupported number of items"),
        };
        Assert.AreEqual(new JsonString(expectedResult), result.AsString);
    }

