        {
            2 => JsonIpV4.Concatenate(buffer, array[0], array[1]),
            3 => JsonIpV4.Concatenate(buffer, array[0], array[1], array[2]),
            4 => JsonIpV4.Concatenate(buffer, array[0], array[1], array[2], array[3]),
            5 => JsonIpV4.Concatenate(buffer, array[0], array[1], array[2], array[3], array[4]),
