    public void Concatenate_JsonIri(string jsonArrayValue, string expectedResult)
    {
        JsonArray array = JsonArray.ParseValue(Encoding.UTF8.GetBytes(jsonArrayValue));
        Span<byte> buffer = stackalloc byte[256];
        JsonIri result = array.GetArrayLength() switch
        {
            2 => JsonIri.Concatenate(buffer, array[0], array[1]),
            3 => JsonIri.Concatenate(buffer, array[0], array[1], array[2]),
            4 => JsonIri.Concatenate(buffer, array[0], array[1], array[2], array[3]),
            5 => JsonIri.Concatenate(buffer, array[0], array[1], array[2], array[3], array[4]),
            6 => JsonIri.Concatenate(buffer, array[0], array[1], array[2], array[3], array[4], array[5]),
            7 => JsonIri.Concatenate(buffer, array[0], array[1], array[2], array[3], array[4], array[5], array[6]),
            8 => JsonIri.Concatenate(buffer, array[0], array[1], array[2], array[3], array[4], array[5], array[6], array[7]),
            _ => throw new InvalidOperationException("Unsupported number of items"),
        };
        Assert.AreEqual(new JsonString(expectedResult), result.AsString);
    }

